      "keystrokes": "cat > /app/polyglot/main.rs << 'EOF'
/*
#ifdef __cplusplus
extern "C" int main(int argc, char** argv){
    // C++ entry point; forward to Rust main via a shim.
    return main(argc, argv);
}
#endif
*/

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let n: u64 = if args.len()>1 { args[1].parse().unwrap_or(0) } else {0};
    let mut a: u64 = 1;
    let mut b: u64 = 1;
    for _ in 0..n {
        let t = a + b;
        a = b;
        b = t;
    }
    println!("{}", a);
}
